xlabel(ax, "Time"); %[output:3b4a51d5]
ylabel(ax, "Probability"); %[output:3b4a51d5]
%[text] Set ranges on the axes.
%ylim(ax, [0, 0.2]);
xlim(ax, [0, nMax]); %[output:3b4a51d5]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:3b4a51d5]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:3b4a51d5]

% histogram for W_q
fig = figure(); %[output:28d6b1e9]
t = tiledlayout(fig,1,1); %[output:28d6b1e9]
ax = nexttile(t); %[output:28d6b1e9]
