ylabel(ax, "Probability"); %[output:28d6b1e9]
pause(2);
exportgraphics(fig, PictureFolder + filesep + "Wq_histogram.pdf"); %[output:28d6b1e9]
ServiceTimes = cellfun(@(q) cellfun(@(c) c.DepartureTime - c.BeginServiceTime, q.Served'), QSamples, UniformOutput=false);
